mapper.select:
select s.id, s.name, no, gender, phone, id_card, is_college, address, degree, graduation_date, clazz_id, c.name as clazz_name, violation_count, violation_score, s.create_time, s.update_time from student s left join clazz c on c.id = s.clazz_id
s.name like concat('%',#{name},'%')
and degree = #{degree}
and clazz_id = #{clazzId}
order by s.create_time desc
